mapper.select:
SELECT count(*)
FROM orders o
LEFT JOIN user_profiles u ON o.customer_id = u.id
LEFT JOIN payment pay ON pay.order_id = o.id
LEFT JOIN shipments sh ON sh.order_id = o.id

    AND o.id = #{id}
    AND o.order_number = #{orderNumber}
    AND o.customer_id = #{customerId}
    AND u.email ILIKE CONCAT('%', #{customerEmail}, '%')
    AND u.phone = #{customerPhone}
    AND o.state_id = #{stateId}
    AND pay.state_id = #{paymentStatus}
    AND sh.state_id = #{shippingStatus}
    AND o.created_time >= #{startDate}
    AND o.created_time <= #{endDate}

SELECT o.id as "orderId", o.order_number as "orderNumber", o.state_id as "orderState", o.total_amount as "totalAmount", o.currency as "currency", o.item_count as "itemCount", o.created_time as "createdTime", o.customer_id as "customerId", u.first_name as "customerFirstName", u.last_name as "customerLastName", u.email as "customerEmail", u.phone as "customerPhone", pay.state_id as "paymentStatus", pay.payment_method as "paymentMethod", pay.amount as "paymentAmount", sh.state_id as "shippingStatus", sh.carrier as "carrier", sh.tracking_number as "trackingNumber", sh.estimated_delivery_date as "estimatedDeliveryDate" FROM orders o LEFT JOIN user_profiles u ON o.customer_id = u.id LEFT JOIN payment pay ON pay.order_id = o.id LEFT JOIN shipments sh ON sh.order_id = o.id
AND o.id = #{id} AND o.order_number = #{orderNumber} AND o.customer_id = #{customerId} AND u.email ILIKE CONCAT('%', #{customerEmail}, '%') AND u.phone = #{customerPhone} AND o.state_id = #{stateId} AND pay.state_id = #{paymentStatus} AND sh.state_id = #{shippingStatus} AND o.created_time >= #{startDate} AND o.created_time <= #{endDate}
${orderby} ${pagination}

SELECT count(*)
FROM order_items oi

    AND oi.order_id = #{orderId}
    AND oi.supplier_id = #{supplierId}
    AND oi.fulfillment_status = #{fulfillmentStatus}

SELECT oi.id as "itemId", oi.order_id as "orderId", oi.product_id as "productId", oi.product_name as "productName", oi.variant_id as "variantId", oi.sku as "sku", oi.quantity as "quantity", oi.unit_price as "unitPrice", oi.total_price as "totalPrice", oi.fulfillment_status as "fulfillmentStatus", oi.supplier_id as "supplierId", p.brand as "brand", p.slug as "productSlug", p.state_id as "productState", p.category_id as "categoryId", c.name as "categoryName", COALESCE(inv.available_quantity, 0) as "currentStock", s.business_name as "supplierName" FROM order_items oi LEFT JOIN products p ON oi.product_id = p.id LEFT JOIN categories c ON p.category_id = c.id LEFT JOIN inventory_item inv ON inv.variant_id = oi.variant_id AND inv.state_id NOT IN ('DISCARDED', 'DAMAGED_SEVERE') LEFT JOIN supplier s ON oi.supplier_id = s.id
AND oi.order_id = #{orderId} AND oi.supplier_id = #{supplierId} AND oi.fulfillment_status = #{fulfillmentStatus}
${orderby} ${pagination}

SELECT count(*)
FROM returnrequest rr
LEFT JOIN orders o ON rr.order_id = o.id

    AND rr.customer_id = #{customerId}
    AND rr.order_id = #{orderId}
    AND rr.state_id = #{stateId}
    AND rr.return_type = #{returnType}
    AND rr.created_time >= #{startDate}
    AND rr.created_time <= #{endDate}

SELECT rr.id as "returnId", rr.order_id as "orderId", rr.customer_id as "customerId", rr.reason as "returnReason", rr.return_type as "returnType", rr.total_refund_amount as "refundAmount", rr.state_id as "returnState", rr.created_time as "returnCreatedTime", o.order_number as "orderNumber", o.total_amount as "orderAmount", o.currency as "orderCurrency", o.state_id as "orderState", o.created_time as "orderCreatedTime", u.first_name as "customerFirstName", u.last_name as "customerLastName", u.email as "customerEmail", u.phone as "customerPhone", pay.state_id as "paymentStatus", pay.payment_method as "paymentMethod" FROM returnrequest rr LEFT JOIN orders o ON rr.order_id = o.id LEFT JOIN user_profiles u ON rr.customer_id = u.id LEFT JOIN payment pay ON pay.order_id = o.id
AND rr.customer_id = #{customerId} AND rr.order_id = #{orderId} AND rr.state_id = #{stateId} AND rr.return_type = #{returnType} AND rr.created_time >= #{startDate} AND rr.created_time <= #{endDate}
${orderby} ${pagination}

SELECT count(*)
FROM support_tickets t

    AND t.customer_id = #{customerId}
    AND t.order_id = #{orderId}
    AND t.state_id = #{stateId}
    AND t.priority = #{priority}
    AND t.assigned_agent_id = #{assignedAgentId}
    AND t.category = #{category}

SELECT t.id as "ticketId", t.subject as "subject", t.state_id as "ticketState", t.priority as "priority", t.category as "category", t.assigned_agent_id as "assignedAgentId", t.created_time as "ticketCreatedTime", t.customer_id as "customerId", u.first_name as "customerFirstName", u.last_name as "customerLastName", u.email as "customerEmail", t.order_id as "orderId", o.order_number as "orderNumber", o.state_id as "orderState", o.total_amount as "orderAmount", o.currency as "orderCurrency", pay.state_id as "paymentStatus", sh.state_id as "shippingStatus", sh.tracking_number as "trackingNumber" FROM support_tickets t LEFT JOIN user_profiles u ON t.customer_id = u.id LEFT JOIN orders o ON t.order_id = o.id LEFT JOIN payment pay ON pay.order_id = o.id LEFT JOIN shipments sh ON sh.order_id = o.id
AND t.customer_id = #{customerId} AND t.order_id = #{orderId} AND t.state_id = #{stateId} AND t.priority = #{priority} AND t.assigned_agent_id = #{assignedAgentId} AND t.category = #{category}
ORDER BY CASE t.priority WHEN 'CRITICAL' THEN 1 WHEN 'HIGH' THEN 2 WHEN 'MEDIUM' THEN 3 ELSE 4 END, t.created_time ASC ${pagination}

SELECT count(*)
FROM settlements st

    AND st.order_id = #{orderId}
    AND st.supplier_id = #{supplierId}
    AND st.state_id = #{stateId}
    AND st.settlement_period_start >= #{startDate}
    AND st.settlement_period_end <= #{endDate}

SELECT st.id as "settlementId", st.order_id as "orderId", st.supplier_id as "supplierId", st.state_id as "settlementState", st.order_amount as "orderAmount", st.commission_amount as "commissionAmount", st.commission_rate as "commissionRate", st.platform_fee as "platformFee", st.tds_amount as "tdsAmount", st.gst_on_commission as "gstOnCommission", st.net_amount as "netAmount", st.currency as "currency", st.settlement_period_start as "periodStart", st.settlement_period_end as "periodEnd", st.created_time as "settlementCreatedTime", o.order_number as "orderNumber", o.state_id as "orderState", o.total_amount as "orderTotal", o.created_time as "orderCreatedTime", s.business_name as "supplierName", pay.state_id as "paymentStatus", pay.payment_method as "paymentMethod", pay.amount as "paymentAmount" FROM settlements st LEFT JOIN orders o ON st.order_id = o.id LEFT JOIN supplier s ON st.supplier_id = s.id LEFT JOIN payment pay ON pay.order_id = o.id
AND st.order_id = #{orderId} AND st.supplier_id = #{supplierId} AND st.state_id = #{stateId} AND st.settlement_period_start >= #{startDate} AND st.settlement_period_end <= #{endDate}
${orderby} ${pagination}

SELECT count(*)
FROM fulfillment_orders fo

    AND fo.order_id = #{orderId}
    AND fo.state_id = #{stateId}
    AND fo.warehouse_id = #{warehouseId}

SELECT fo.id as "fulfillmentId", fo.order_id as "orderId", fo.state_id as "fulfillmentState", fo.priority as "priority", fo.fulfillment_type as "fulfillmentType", fo.total_items as "totalItems", fo.assigned_picker_id as "assignedPicker", fo.assigned_packer_id as "assignedPacker", fo.pick_started_at as "pickStartedAt", fo.pick_completed_at as "pickCompletedAt", fo.pack_started_at as "packStartedAt", fo.pack_completed_at as "packCompletedAt", fo.shipped_at as "shippedAt", fo.carrier as "carrier", fo.tracking_number as "trackingNumber", fo.estimated_ship_date as "estimatedShipDate", fo.estimated_delivery_date as "estimatedDeliveryDate", fo.created_time as "fulfillmentCreatedTime", fo.warehouse_id as "warehouseId", w.warehouse_name as "warehouseName", w.warehouse_code as "warehouseCode", w.city as "warehouseCity", o.order_number as "orderNumber", o.state_id as "orderState", o.total_amount as "orderAmount", o.customer_id as "customerId" FROM fulfillment_orders fo LEFT JOIN warehouses w ON fo.warehouse_id = w.id LEFT JOIN orders o ON fo.order_id = o.id
AND fo.order_id = #{orderId} AND fo.state_id = #{stateId} AND fo.warehouse_id = #{warehouseId}
${orderby} ${pagination}
